const ctx = $input.first().json || {};

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'cc_report',
  event: 'completed',
  cc_id: ctx.cc_id || 'unknown',
  type: ctx.type || 'unknown',
  level: 'info'
}));

return {
  statusCode: 201,
  body: { message: 'GET A NEW CC_REPORT BY CC id' }
};

// Prepara delete em lote com escaping padronizado
const diff = $input.first().json;
const toDelete = diff.to_delete || [];

if (toDelete.length === 0) {
  return [{ json: { _skip_delete: true, cc_id: diff.cc_id, type: diff.type } }];
}

const esc = (v) => String(v ?? '').replace(/'/g, "''");
const ids_sql = toDelete.map((id) => `'${esc(id)}'`).join(', ');

return [{
  json: {
    _skip_delete: false,
    cc_id: diff.cc_id,
    type: diff.type,
    delete_count: toDelete.length,
    ids_sql
  }
}];

// Prepara insert em lote com escaping padronizado
const diff = $input.first().json;
const toInsert = diff.to_insert || [];

if (toInsert.length === 0) {
  return [{ json: { _skip_insert: true, cc_id: diff.cc_id, type: diff.type } }];
}

const esc = (v) => String(v ?? '').replace(/'/g, "''");
const num = (v, fallback = 0) => {
  const n = Number(String(v ?? '').replace(',', '.'));
  return Number.isFinite(n) ? n : fallback;
};

const values_sql = toInsert.map((rec) => {
  const venc = num(rec.VENCIMENTO, 0);
  const valor = num(rec.VALOR, 0);
  return `(
  '${esc(rec.ID)}',
  '${esc(rec.ID_SEED)}',
  '${esc(rec.CC)}',
  '${esc(rec.ID_CC)}',
  '${esc(rec.CC_LABEL)}',
  to_timestamp(${venc})::timestamp,
  '${esc(rec.FORNECEDOR)}',
  '${esc(rec.NOME_DESPESA)}',
  '${esc(rec.SITUACAO)}',
  (NOW() AT TIME ZONE 'America/Sao_Paulo')::timestamp,
  '${esc(rec.CATEGORIA)}',
  ${valor},
  '${esc(rec.TYPE)}',
  (NOW() AT TIME ZONE 'America/Sao_Paulo')::timestamp,
  (NOW() AT TIME ZONE 'America/Sao_Paulo')::timestamp
)`;
}).join(',\n');

return [{
  json: {
    _skip_insert: false,
    cc_id: diff.cc_id,
    type: diff.type,
    insert_count: toInsert.length,
    values_sql
  }
}];

// Calcula diff entre extensão e DB com leitura direta dos nós para evitar merge custoso
const currentRecords = $items('Normalizar Registros', 0, 0)
  .map(item => item.json)
  .filter(r => r && !r._empty && r.ID);

const dbRecords = $input.all()
  .map(item => item.json)
  .filter(r => r && r.id);

const extensionIds = new Set(currentRecords.map(r => r.ID));
const currentData = Object.fromEntries(currentRecords.map(r => [r.ID, r]));
const dbIds = new Set(dbRecords.map(r => r.id));

const toInsert = [];
for (const id of extensionIds) {
  if (!dbIds.has(id)) toInsert.push(currentData[id]);
}

const toDelete = [];
for (const id of dbIds) {
  if (!extensionIds.has(id)) toDelete.push(id);
}

const ccId = currentRecords[0]?.ID_CC || $('Selecionar Contexto').item.json.cc_id || '';
const type = currentRecords[0]?.TYPE || $('Selecionar Contexto').item.json.type || '';

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'cc_report',
  event: 'diff_calculated',
  cc_id: ccId,
  type: type,
  extension_count: currentRecords.length,
  db_count: dbRecords.length,
  to_insert: toInsert.length,
  to_delete: toDelete.length,
  level: 'info'
}));

return {
  json: {
    cc_id: ccId,
    type: type,
    to_insert: toInsert,
    to_delete: toDelete,
    has_changes: toInsert.length > 0 || toDelete.length > 0
  }
};

// Reduz execução redundante: passa apenas contexto necessário para query única no DB
const first = $input.first().json;
return [{
  json: {
    cc_id: first.ID_CC,
    type: first.TYPE
  }
}];

// Verifica se página é válida e formata registros
const ctx = $input.first().json.payload;
const data = ctx.data;

if (!data.source || !data.source.subItens || !data.source.subItens.ID1) {
  console.log(JSON.stringify({
    timestamp: new Date().toISOString(),
    route: 'cc_report',
    event: 'invalid_page',
    cc_id: ctx.cc_id,
    level: 'warn'
  }));
  return [{ json: { _empty: true, cc_id: ctx.cc_id, type: ctx.type } }];
}

const source = data.source;
const ccLabel = source.itens[0].CentroCustos;
const subItens = source.subItens.ID1;
const ccId = ctx.cc_id;
const type = ctx.type;

function generateIdToken(seed) {
  let hash = 0;
  for (let i = 0; i < seed.length; i++) {
    const char = seed.charCodeAt(i);
    hash = ((hash << 5) - hash) + char;
    hash = hash & hash;
  }
  return Math.abs(hash).toString(16);
}

function extractCcValue(input) {
  const match = String(input || '').match(/CC[-\s]*(\d+)/);
  return match ? match[1] : '-1';
}

function extractNumericPart(input) {
  const match = String(input || '').match(/\b(\d{6})\b/);
  return match ? match[1] : '-1';
}

function extractPrefix(input) {
  const match = String(input || '').match(/^[A-Z]{2}-[A-Z0-9]{3}/);
  return match ? match[0] : '-1';
}

function extractCcTextValue(input) {
  const normalized = String(input || '');
  const index = normalized.indexOf('CC-');
  return index !== -1 ? normalized.slice(index + 3, index + 9) : '-1';
}

function extractCcTextValueExceptions(input) {
  const normalized = String(input || '').replace(/\//g, '');
  const index = normalized.indexOf('CC-');
  if (index === -1) return '-1';
  const endIndex = normalized.indexOf('/', index);
  return endIndex === -1 ? normalized.slice(index + 3, index + 9) : normalized.slice(index + 3, endIndex);
}

function getCcLabel(labelText) {
  if (labelText === 'RT - Vendas') return 'Vendas';
  if (labelText === 'Marketing') return 'Marketing';
  if (labelText === 'Vendas') return 'Vendas';
  if (labelText === 'Administração') return 'Administração';

  let label = extractCcValue(labelText);
  if (label === '-1') {
    label = extractNumericPart(labelText);
    if (label === '-1') {
      label = extractPrefix(labelText);
      if (label === '-1') {
        label = extractCcTextValue(labelText);
        if (label === '-1') {
          label = extractCcTextValueExceptions(labelText);
        }
      }
    }
  }
  return label;
}

// Mantém a mesma semântica de índice para itens idênticos, porém em O(n)
function annotateWithStableIndex(arr) {
  const signatureToIndex = new Map();
  let nextIndex = 0;

  return arr.map((item) => {
    const signature = JSON.stringify(item);
    if (!signatureToIndex.has(signature)) {
      signatureToIndex.set(signature, nextIndex++);
    }

    return { index: signatureToIndex.get(signature), ...item };
  });
}

const flattened = annotateWithStableIndex(subItens);
const ccSemantic = getCcLabel(ccLabel);

const formattedRecords = flattened.map(item => {
  const INDEX = item.index;
  const VENCIMENTO = item.Vencimento;
  const FORNECEDOR = item.Fornecedor;
  const NOME_DESPESA = item.NomeDespesa;
  const SITUACAO = item.Situacao;
  const VALOR = item.Valor;
  const CATEGORIA = item.Categoria;

  const SEED = `${INDEX}-${ccId}-${NOME_DESPESA}-${VENCIMENTO}-${FORNECEDOR}-${VALOR}-${SITUACAO}-${type}-${CATEGORIA}`;
  const TOKEN = generateIdToken(SEED);

  return {
    json: {
      ID: TOKEN,
      ID_SEED: SEED,
      CC: ccSemantic,
      CC_LABEL: ccLabel,
      ID_CC: ccId,
      VENCIMENTO: VENCIMENTO,
      FORNECEDOR: FORNECEDOR,
      NOME_DESPESA: NOME_DESPESA,
      SITUACAO: SITUACAO,
      CATEGORIA: CATEGORIA,
      VALOR: VALOR,
      TYPE: type
    }
  };
});

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'cc_report',
  event: 'records_formatted',
  cc_id: ccId,
  type: type,
  count: formattedRecords.length,
  level: 'info'
}));

if (formattedRecords.length === 0) {
  return [{ json: { _empty: true, cc_id: ccId, type: type } }];
}

return formattedRecords;

// Guard de early-exit antes de decode profundo
const ctx = $input.first().json;
const payload = ctx.payload || {};

if (!payload.data || !payload.data.source || !payload.data.source.subItens || !payload.data.source.subItens.ID1) {
  console.log(JSON.stringify({
    timestamp: new Date().toISOString(),
    route: 'cc_report',
    event: 'early_empty_before_decode',
    cc_id: payload.cc_id || 'unknown',
    level: 'info'
  }));

  return {
    payload: {
      cc_id: payload.cc_id,
      type: payload.type,
      data: { source: null }
    }
  };
}

function decodeHtml(obj) {
  if (typeof obj === 'string') {
    return obj
      .replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>')
      .replace(/&quot;/g, '"').replace(/&#39;/g, "'").replace(/&#x27;/g, "'")
      .replace(/&#x2F;/g, '/').replace(/&nbsp;/g, ' ');
  }
  if (Array.isArray(obj)) return obj.map(decodeHtml);
  if (typeof obj === 'object' && obj !== null) {
    const out = {};
    for (const k in obj) out[k] = decodeHtml(obj[k]);
    return out;
  }
  return obj;
}

const decoded = decodeHtml(payload);

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'cc_report',
  event: 'decoded_html',
  cc_id: decoded.cc_id,
  level: 'info'
}));

return { payload: decoded };

// Valida payload da extensão
const input = $input.first().json;
const body = input.body || input;

if (!body.data || !body.type || !body.cc_id) {
  return {
    _valid: false,
    statusCode: 400,
    body: { error: 'Missing required fields: data, type, cc_id' }
  };
}

if (body.type !== 'entrada' && body.type !== 'saida') {
  return {
    _valid: false,
    statusCode: 400,
    body: { error: 'Invalid type: must be entrada or saida' }
  };
}

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'cc_report',
  event: 'input_validated',
  cc_id: body.cc_id,
  type: body.type,
  level: 'info'
}));

return { _valid: true, payload: body };
